def dot_loop(a, b):
    if len(a) != len(b):
        raise ValueError(f"Length mismatch: {len(a)} vs {len(b)}")
    result = 0.0
    for x, y in zip(a, b):
        result += x * y
    return result


import numpy as np

def dot_numpy(a, b):
    a = np.asarray(a, dtype=float)
    b = np.asarray(b, dtype=float)
    if a.shape != b.shape:
        raise ValueError(f"Shape mismatch: {a.shape} vs {b.shape}")
    return float(np.sum(a * b))

